(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["home14"],{ae61:function(n,t,r){"use strict";r.r(t);var e=function(){var n=this,t=n.$createElement,e=n._self._c||t;return e("markdown",{attrs:{source:r("d184")}})},a=[],p=r("2877"),s={},c=Object(p["a"])(s,e,a,!1,null,null,null);t["default"]=c.exports},d184:function(n,t){n.exports='### javascript代码块概念及预编译机制\n\nJavaScript是一种描述型脚本语言，它不同于java或C#等编译性语言,它不需要进行编译成中间语言,而是由浏览器进行动态地解析与执行。如果你不能理解javaScript语言的运行机制，或者简单地说，你不能掌握javascript的执行顺序，那你就犹如伯乐驾驭不了千里马，让千里马脱缰而出，四处乱窜。\n\n那么JavaScript是怎么来进行解析的吗？它的执行顺序又是如何的呢？在了解这些之前，我们先来认识几个重要的术语：\n\n#### 1、代码块\n\nJavaScript中的代码块是指由script标签分割的代码段。例如：\n```html\n<script type="text/javascript">\n      alert("这是代码块一");\n<\/script>\n<script type="text/javascript">\n      alert("这是代码块二");\n<\/script>\n```\n\nJS是按照代码块来进行编译和执行的，代码块间相互独立，但变量和方法共享。什么意思呢? 举个例子，你就明白了：\n```html\n<script type="text/javascript">\n      alert(str);//因为没有定义str，所以浏览器会出错，下面的不能运行\n      alert("我是代码块一");//没有运行到这里\n      var test = "我是代码块一变量";\n<\/script>\n<script type="text/javascript">\n      alert("我是代码块二"); //这里有运行到\n      alert(test); //弹出"我是代码块一变量"\n<\/script>\n```\n上面的代码中代码块一中运行报错，但不影响代码块二的执行，这就是代码块间的独立性，而代码块二中能调用到代码一中的变量，则是块间共享性。\n\n\n#### 2、声明式函数与赋值式函数\nJS中的函数定义分为两种：声明式函数与赋值式函数。\n```html\n<script type="text/javascript">\n     function Fn(){ //声明式函数\n             \n     }\n         \n     var Fn = function{  //赋值式函数\n             \n     }\n<\/script>\n```\n声明式函数与赋值式函数的区别在于：在JS的预编译期，声明式函数将会先被提取出来，然后才按顺序执行js代码。\n\n#### 3、预编译期与执行期\n\n事实上，JS的解析过程分为两个阶段：预编译期(预处理)与执行期。\n\n预编译期JS会对本代码块中的所有声明的变量和函数进行处理（类似与C语言的编译），但需要注意的是此时处理函数的只是声明式函数，而且变量也只是进行了声明但未进行初始化以及赋值。\n\n```html\n<script type="text/javascript">\n     Fn();  //执行结果："执行了函数2",同名函数后者会覆盖前者\n     function Fn(){ //函数1\n        alert("执行了函数1");\n     }\n         \n     function Fn(){  //函数2\n        alert("执行了函数2");\n     }\n<\/script>\n\n<script type="text/javascript">\n      Fn();  //执行结果："执行了声明式函数",在预编译期声明函数及被处理了，所以即使Fn()调用函数放在声明函数前也能执行。\n      function Fn(){ //声明式函数\n         alert("执行了声明式函数");\n      }\n         \n      var Fn = function(){  //赋值式函数\n         alert("执行了赋值式函数");\n      }\n<\/script>\n\n\x3c!-- 代码块一 --\x3e\n<script type="text/javascript">\n      alert(str);//浏览器报错,但并没有弹出信息窗\n<\/script>\n\x3c!-- 代码块二 --\x3e\n<script type="text/javascript">\n      alert(str); //弹窗"undefined"\n      var str = "aaa";\n<\/script>\n\x3c!-- js在预处理期对变量进行了声明处理,但是并没有进行初始化与赋值，所以导致代码块二中的变量是unfiened的，而代码一中的变量是完全不存在的，所以浏览器报错。 --\x3e\n```\n理解了上面的几个术语，相信大家对JS的运行机制已经有了个大概的印象了，现在我们来看个例子:\n```html\n<script type="text/javascript">\n      Fn();  //浏览器报错:"undefined"\n<\/script>\n<script type="text/javascript">\n      function Fn(){ //函数1\n          alert("执行了函数1");\n      }\n<\/script>\n```\n为什么运行上面的代码浏览器会报错呢？声明函数不是会在预处理期就会被处理了吗，怎么还会找不到Fn()函数呢？其实这是一个理解误点，我们上面说了JS引擎是按照代码块来顺序执行的，其实完整的说应该是按照代码块来进行预处理和执行的，也就是说预处理的只是执行到的代码块的声明函数和变量，而对于还未加载的代码块，是没法进行预处理的，这也是边编译边处理的核心所在。\n\n现在，让我们来总结整理下：\n```\nstep 1. 读入第一个代码块。\n\nstep 2. 做语法分析，有错则报语法错误（比如括号不匹配等），并跳转到step5。\n\nstep 3. 对var变量和function定义做“预编译处理”（永远不会报错的，因为只解析正确的声明）。\n\nstep 4. 执行代码段，有错则报错（比如变量未定义）。\n\nstep 5. 如果还有下一个代码段，则读入下一个代码段，重复step2。\n\nstep6. 结束。\n```\n\n而根据HTML文档流的执行顺序，需要在页面元素渲染前执行的js代码应该放在前面的script代码块中，而需要在页面元素加载完后的js放在元素后面，body标签的onload事件是在最后执行的。\n```html\n<script type="text/javascript">\n    alert("first");\n    function Fn(){\n        alert("third");\n    }\n<\/script>     \n \n<script type="text/javascript">\n    alert("second");\n<\/script>\n```\n\n'}}]);